// Decide which step is due based on time-since-masterclass-end per campaign.
const now = Date.now();
const out = [];
for (const c of $json.campaigns ?? []) {
  const endMs = new Date(c.masterclass_ended_at).getTime();
  const dt = (now - endMs) / 3_600_000;
  let step;
  if (dt >= 0 && dt < 6) step = 'offer_d0';
  else if (dt >= 24 && dt < 30) step = 'offer_d1';
  else if (dt >= 48 && dt < 54) step = 'offer_d2_morning';
  else if (dt >= 68 && dt < 72) step = 'offer_d2_final';
  if (step) out.push({ json: { campaign_id: c.id, step }});
}
return out;

const { createHmac } = require('crypto');
const body = JSON.stringify($json);
const ts = Math.floor(Date.now()/1000).toString();
const sig = createHmac('sha256', $env.N8N_WEBHOOK_SECRET).update(`${ts}.${body}`).digest('hex');
return [{ json: { body, ts, sig } }];
